    name = request.args.get('name')
    bio = request.args.get('bio')
    location = request.args.get('location')
    status = request.args.get('status')
    
    # Convert markdown text to HTML
    bio_html = markdown.markdown(bio, extensions=['nl2br', 'sane'])
    status_html = markdown.markdown(status, extensions=['nl2br', 'sane'])
    
    # Render the dashboard template with user information
    return render_template('welcome.html', name=name, bio=bio_html, location=location, status=status_html)